svg.script:
    (function () {
      var root = document.querySelector('svg > g[id], g[id]');
      if (!root) {
        return;
      }

      var ignoredClasses = {
        'legend-item-container': true,
        'legend-label': true,
        'legend-item': true,
        'legend-row': true,
        'slice': true,
        'track': true,
        'tracks': true,
        'bars': true,
        'data-series': true,
        'series-lines': true,
        'chart-area': true,
        'chart-header': true,
        'chart-title': true,
        'axis-labels': true,
        'gridlines': true,
        'value-labels-inner': true,
        'value-labels-outer': true,
        'chart-color-1': true,
        'chart-color-2': true,
        'chart-color-3': true,
        'chart-color-4': true,
        'chart-color-5': true,
        'chart-color-6': true
      };

      function firstSeriesClass(element) {
        if (!element || !element.classList) {
          return null;
        }

        for (var i = 0; i < element.classList.length; i += 1) {
          var className = element.classList[i];
          if (!ignoredClasses[className]) {
            return className;
          }
        }

        return null;
      }

      function legendSeries(item) {
        var swatch = item.querySelector('circle[class], rect[class]:not(.legend-item-container), line[class], polyline[class], path[class], ellipse[class], polygon[class]');
        return firstSeriesClass(swatch);
      }

      var slices = root.querySelectorAll('.slice');
      var labels = root.querySelectorAll('.value-labels-inner');
      var legendItems = Array.prototype.slice.call(root.querySelectorAll('.legend-item')).filter(function (item) {
        return !!legendSeries(item);
      });

      if (legendItems.length === 0) {
        return;
      }

      var seriesNames = [];
      legendItems.forEach(function (item) {
        var series = legendSeries(item);
        item.setAttribute('data-series', series);
        if (!item.hasAttribute('tabindex')) {
          item.setAttribute('tabindex', '0');
        }
        item.style.cursor = 'pointer';

        var container = item.querySelector('rect.legend-item-container');
        if (container) {
          container.style.transition = 'opacity 220ms ease-in-out, stroke 220ms ease-in-out, stroke-width 220ms ease-in-out';
        }

        var label = item.querySelector('text.legend-label');
        if (label) {
          label.style.transition = 'opacity 220ms ease-in-out';
        }

        if (seriesNames.indexOf(series) === -1) {
          seriesNames.push(series);
        }
      });

      function assignLabelSeries() {
        Array.prototype.forEach.call(labels, function (label) {
          if ((label.getAttribute && label.getAttribute('data-series')) || label.closest('.legend')) {
            return;
          }

          var labelBox = label.getBBox();
          var labelX = labelBox.x + (labelBox.width / 2);
          var labelY = labelBox.y + (labelBox.height / 2);
          var nearestSeries = null;
          var nearestDistance = Infinity;

          slices.forEach(function (slice) {
            var sliceSeries = firstSeriesClass(slice);
            if (!sliceSeries || seriesNames.indexOf(sliceSeries) === -1) {
              return;
            }

            var sliceBox = slice.getBBox();
            var sliceX = sliceBox.x + (sliceBox.width / 2);
            var sliceY = sliceBox.y + (sliceBox.height / 2);
            var dx = labelX - sliceX;
            var dy = labelY - sliceY;
            var distance = (dx * dx) + (dy * dy);

            if (distance < nearestDistance) {
              nearestDistance = distance;
              nearestSeries = sliceSeries;
            }
          });

          if (nearestSeries) {
            label.setAttribute('data-series', nearestSeries);
            label.style.transition = 'opacity 220ms ease-in-out, font-size 220ms ease-in-out, fill-opacity 220ms ease-in-out';
          }
        });
      }

      assignLabelSeries();

      var elementsBySeries = {};
      seriesNames.forEach(function (series) {
        elementsBySeries[series] = [];
      });

      Array.prototype.forEach.call(root.querySelectorAll('*'), function (element) {
        if (element.closest('.legend')) {
          return;
        }

        var series = null;
        if (element.hasAttribute && element.hasAttribute('data-series')) {
          var dataSeries = element.getAttribute('data-series');
          if (seriesNames.indexOf(dataSeries) !== -1) {
            series = dataSeries;
          }
        }

        if (!series) {
          series = firstSeriesClass(element);
        }

        if (!series) {
          var ancestor = element.parentElement;
          while (ancestor && ancestor !== root && !series) {
            if (ancestor.hasAttribute && ancestor.hasAttribute('data-series')) {
              var ancestorDataSeries = ancestor.getAttribute('data-series');
              if (seriesNames.indexOf(ancestorDataSeries) !== -1) {
                series = ancestorDataSeries;
                break;
              }
            }

            var ancestorSeries = firstSeriesClass(ancestor);
            if (ancestorSeries && seriesNames.indexOf(ancestorSeries) !== -1) {
              series = ancestorSeries;
              break;
            }

            ancestor = ancestor.parentElement;
          }
        }

        if (!series || seriesNames.indexOf(series) === -1) {
          return;
        }

        elementsBySeries[series].push(element);
        element.style.transition = 'opacity 220ms ease-in-out, fill-opacity 220ms ease-in-out, stroke-opacity 220ms ease-in-out';
      });

      function clearActiveSeries() {
        legendItems.forEach(function (item) {
          item.style.removeProperty('opacity');
          var container = item.querySelector('rect.legend-item-container');
          if (container) {
            container.style.removeProperty('stroke');
            container.style.removeProperty('stroke-width');
          }
        });

        seriesNames.forEach(function (series) {
          elementsBySeries[series].forEach(function (element) {
            element.style.removeProperty('opacity');
          });
        });

        labels.forEach(function (label) {
          var isHoverOnly = label.classList.contains('hover-only');
          label.style.opacity = isHoverOnly ? '0' : '';
          label.style.removeProperty('font-size');
          label.style.removeProperty('font-weight');
          label.style.removeProperty('fill-opacity');
        });
      }

      function setActiveSeries(series) {
        var isSingleSeries = seriesNames.length === 1;

        legendItems.forEach(function (item) {
          var isActive = item.getAttribute('data-series') === series;
          item.style.opacity = isActive ? '1' : '0.4';

          var container = item.querySelector('rect.legend-item-container');
          if (container) {
            container.style.stroke = isActive ? 'var(--color-text-dark)' : '';
            container.style.strokeWidth = isActive ? '1.5' : '';
          }
        });

        seriesNames.forEach(function (name) {
          var isActive = name === series;
          elementsBySeries[name].forEach(function (element) {
            if (isSingleSeries) {
              element.style.fillOpacity = isActive ? '1' : '0.25';
              element.style.strokeOpacity = isActive ? '1' : '0.25';
              element.style.removeProperty('opacity');
            } else {
              element.style.opacity = isActive ? '1' : '0.25';
              element.style.removeProperty('fill-opacity');
              element.style.removeProperty('stroke-opacity');
            }
          });
        });

        labels.forEach(function (label) {
          var isActive = label.getAttribute && label.getAttribute('data-series') === series;
          if (isActive) {
            label.style.opacity = '1';
            label.style.fontSize = '14px';
            label.style.fontWeight = '700';
            label.style.fillOpacity = '1';
          } else {
            var isHoverOnly = label.classList.contains('hover-only');
            label.style.opacity = isHoverOnly ? '0' : '';
            label.style.removeProperty('font-size');
            label.style.removeProperty('font-weight');
            label.style.removeProperty('fill-opacity');
          }
        });
      }

      legendItems.forEach(function (item) {
        var series = item.getAttribute('data-series');

        item.addEventListener('mouseenter', function () {
          setActiveSeries(series);
        });

        item.addEventListener('mouseleave', clearActiveSeries);

        item.addEventListener('focus', function () {
          setActiveSeries(series);
        });

        item.addEventListener('blur', clearActiveSeries);
      });

      slices.forEach(function (slice) {
        var series = null;

        legendItems.forEach(function (item) {
          var itemSeries = item.getAttribute('data-series');
          if (!series && slice.classList.contains(itemSeries)) {
            series = itemSeries;
          }
        });

        if (!series) {
          return;
        }

        slice.addEventListener('mouseenter', function () {
          setActiveSeries(series);
        });

        slice.addEventListener('mouseleave', clearActiveSeries);
      });
    }());
